    let mut map: HashMap<String, i32> = HashMap::new();
    map.insert("alice".to_string(), 90);
    map.insert("bob".to_string(), 85);

    println!("{:?}", map.get("alice"));  // Some(90)
    println!("{}", map["bob"]);          // 85
    println!("{}", map.contains_key("charlie"));  // false
    println!("{}", map.len());  // 2
}

