fn main() {
    let words = vec!["apple", "banana", "apple", "cherry", "banana", "apple"];
    let mut freq: HashMap<&str, i32> = HashMap::new();

    for word in &words {
        *freq.entry(word).or_insert(0) += 1;
    }

    println!("{:?}", freq);
    // {"apple": 3, "banana": 2, "cherry": 1}
}

